import hashlib
import requests
import os

def consistent_hash(url):
    return int(hashlib.md5(url.encode()).hexdigest(), 16) % 10000

def download_image(image_id):
    url = f"https://picsum.photos/id/{image_id}/200/300"
    filename = f"image_{consistent_hash(url)}.jpg"
    filepath = os.path.join("downloaded_images_fast", filename)

    response = requests.get(url)
    response.raise_for_status()

    with open(filepath, 'wb') as f:
        f.write(response.content)

    print(f"Downloaded {filename}")

def main():
    # Clear directory first
    import glob
    for f in glob.glob("downloaded_images_fast/*"):
        os.remove(f)

    # Download images sequentially
    for i in range(1, 10):
        download_image(i)

if __name__ == "__main__":
    main()
EOF
